# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

import os
import tensorflow as tf
from tensorflow import keras
from flask import Flask, request, jsonify
import pandas as pd
import numpy as np
from werkzeug.utils import secure_filename
import io
from PIL import Image
import json
from datetime import datetime

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
MODEL_FOLDER = 'models'
TRAINING_DATA_FOLDER = 'training_data'
ALLOWED_EXTENSIONS = {'csv', 'png', 'jpg', 'jpeg'}

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_FOLDER, exist_ok=True)
os.makedirs(TRAINING_DATA_FOLDER, exist_ok=True)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 50 * 1024 * 1024

model = None
training_history = []

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def create_model(input_shape, num_classes):
    model = keras.Sequential([
        keras.layers.Input(shape=input_shape),
        keras.layers.Conv2D(32, (3, 3), activation='relu'),
        keras.layers.MaxPooling2D((2, 2)),
        keras.layers.Conv2D(64, (3, 3), activation='relu'),
        keras.layers.MaxPooling2D((2, 2)),
        keras.layers.Conv2D(64, (3, 3), activation='relu'),
        keras.layers.Flatten(),
        keras.layers.Dense(64, activation='relu'),
        keras.layers.Dropout(0.5),
        keras.layers.Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam',
                  loss='sparse_categorical_crossentropy',
                  metrics=['accuracy'])
    return model

def load_image(file_path, target_size=(128, 128)):
    img = Image.open(file_path).convert('RGB')
    img = img.resize(target_size)
    img_array = np.array(img) / 255.0
    return img_array

def load_csv_data(csv_path):
    df = pd.read_csv(csv_path)
    return df

@app.route('/upload_csv', methods=['POST'])
def upload_csv():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        filename = f"{timestamp}_{filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)
        
        df = load_csv_data(filepath)
        
        return jsonify({
            'message': 'CSV uploaded successfully',
            'filename': filename,
            'rows': len(df),
            'columns': list(df.columns)
        }), 200
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/upload_training_image', methods=['POST'])
def upload_training_image():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    label = request.form.get('label', 'unknown')
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        filename = f"{label}_{timestamp}_{filename}"
        
        label_folder = os.path.join(TRAINING_DATA_FOLDER, label)
        os.makedirs(label_folder, exist_ok=True)
        
        filepath = os.path.join(label_folder, filename)
        file.save(filepath)
        
        return jsonify({
            'message': 'Training image uploaded successfully',
            'filename': filename,
            'label': label
        }), 200
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/train_model', methods=['POST'])
def train_model():
    global model
    
    data = request.get_json()
    epochs = data.get('epochs', 10)
    batch_size = data.get('batch_size', 32)
    image_size = data.get('image_size', [128, 128])
    
    labels = os.listdir(TRAINING_DATA_FOLDER)
    if not labels:
        return jsonify({'error': 'No training data available'}), 400
    
    X_train = []
    y_train = []
    
    label_map = {label: idx for idx, label in enumerate(labels)}
    
    for label in labels:
        label_folder = os.path.join(TRAINING_DATA_FOLDER, label)
        if not os.path.isdir(label_folder):
            continue
        
        for img_file in os.listdir(label_folder):
            img_path = os.path.join(label_folder, img_file)
            try:
                img_array = load_image(img_path, tuple(image_size))
                X_train.append(img_array)
                y_train.append(label_map[label])
            except Exception as e:
                print(f"Error loading {img_path}: {e}")
    
    if len(X_train) == 0:
        return jsonify({'error': 'No valid training images found'}), 400
    
    X_train = np.array(X_train)
    y_train = np.array(y_train)
    
    if model is None:
        model = create_model(input_shape=(*image_size, 3), num_classes=len(labels))
    
    history = model.fit(X_train, y_train, epochs=epochs, batch_size=batch_size, validation_split=0.2)
    
    model_path = os.path.join(MODEL_FOLDER, f'model_{datetime.now().strftime("%Y%m%d_%H%M%S")}.h5')
    model.save(model_path)
    
    training_record = {
        'timestamp': datetime.now().isoformat(),
        'epochs': epochs,
        'batch_size': batch_size,
        'samples': len(X_train),
        'accuracy': float(history.history['accuracy'][-1]),
        'val_accuracy': float(history.history['val_accuracy'][-1]),
        'model_path': model_path,
        'labels': labels
    }
    training_history.append(training_record)
    
    return jsonify({
        'message': 'Model trained successfully',
        'training_info': training_record
    }), 200

@app.route('/predict', methods=['POST'])
def predict():
    global model
    
    if model is None:
        return jsonify({'error': 'Model not trained yet'}), 400
    
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        img = Image.open(io.BytesIO(file.read())).convert('RGB')
        img = img.resize((128, 128))
        img_array = np.array(img) / 255.0
        img_array = np.expand_dims(img_array, axis=0)
        
        predictions = model.predict(img_array)
        predicted_class = int(np.argmax(predictions[0]))
        confidence = float(predictions[0][predicted_class])
        
        labels = os.listdir(TRAINING_DATA_FOLDER)
        predicted_label = labels[predicted_class] if predicted_class < len(labels) else 'unknown'
        
        return jsonify({
            'predicted_class': predicted_class,
            'predicted_label': predicted_label,
            'confidence': confidence,
            'all_predictions': predictions[0].tolist()
        }), 200
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/load_model', methods=['POST'])
def load_model_endpoint():
    global model
    
    data = request.get_json()
    model_path = data.get('model_path')
    
    if not model_path or not os.path.exists(model_path):
        return jsonify({'error': 'Model file not found'}), 400
    
    try:
        model = keras.models.load_model(model_path)
        return jsonify({'message': 'Model loaded successfully', 'model_path': model_path}), 200
    except Exception as e:
        return jsonify({'error': f'Failed to load model: {str(e)}'}), 500

@app.route('/training_history', methods=['GET'])
def get_training_history():
    return jsonify({'history': training_history}), 200

@app.route('/dataset_info', methods=['GET'])
def dataset_info():
    labels = os.listdir(TRAINING_DATA_FOLDER)
    dataset_stats = {}
    
    for label in labels:
        label_folder = os.path.join(TRAINING_DATA_FOLDER, label)
        if os.path.isdir(label_folder):
            count = len([f for f in os.listdir(label_folder) if allowed_file(f)])
            dataset_stats[label] = count
    
    return jsonify({
        'total_classes': len(dataset_stats),
        'class_distribution': dataset_stats,
        'total_samples': sum(dataset_stats.values())
    }), 200

@app.route('/contribute_batch', methods=['POST'])
def contribute_batch():
    files = request.files.getlist('files')
    labels = request.form.getlist('labels')
    
    if len(files) != len(labels):
        return jsonify({'error': 'Number of files and labels must match'}), 400
    
    uploaded_files = []
    
    for file, label in zip(files, labels):
        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            timestamp = datetime.now().strftime('%Y%m%d_%H%M%S_%f')
            filename = f"{label}_{timestamp}_{filename}"
            
            label_folder = os.path.join(TRAINING_DATA_FOLDER, label)
            os.makedirs(label_folder, exist_ok=True)
            
            filepath = os.path.join(label_folder, filename)
            file.save(filepath)
            uploaded_files.append({'filename': filename, 'label': label})
    
    return jsonify({
        'message': f'Successfully uploaded {len(uploaded_files)} training examples',
        'files': uploaded_files
    }), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)